  ('promotion-1487eb6c-moex-00012', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '中央政府戊機關於X年9月發生下列交易事項：退還以前年度已繳庫收入數5萬元、收到以前年 度剔除經費並辦理繳庫 10 萬元，以及使用以前年度購置之材料，將其價款以本年度預算數辦理 繳庫20萬元。依中央政府普通公務單位會計制度之一致規定，相關交易對戊機關於9月帳列「繳 付公庫數」科目的影響，為下列何者？', '["增加15萬元", "增加25萬元", "增加30萬元", "增加35萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00013', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依政府會計準則公報第4號規定，中央政府乙機關1部機械設備成本10萬元，已計提折舊5萬 元，於X年9月1日與B公司約定以不具商業實質形式向B公司換入電腦1部，當日機械設備 及電腦的市場行情各為6萬元及7萬元，則乙機關換入資產之入帳金額為下列何者？', '["5萬元", "6萬元", "7萬元", "10萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00014', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '甲機關投資持有A上市公司14%股權，依政府會計準則公報第5號「政府長期股權投資之會計處 理」之規定，請問甲機關對此長期股權投資辦理續後評價時，具重大影響力和未具重大影響力， 應分別採用何種方法？', '["收益法、成本法", "權益法、按投資之公允價值評價", "均為權益法", "均為按投資之公允價值評價 12140"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00015', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '甲機關X4年度對A上市公司之投資比例為19%，具重大影響力，依中央政府普通公務單位會計 制度之一致規定，下列有關甲機關X4年度長期投資之敘述，何者錯誤？', '["對A上市公司之投資，帳列其他長期投資科目", "對A上市公司之投資，帳列採權益法之投資科目", "收到A上市公司發放之現金股利並繳庫，應借記繳付公庫數科目", "年度終了評價，較帳面金額增加部分，應貸記投資利益科目"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00016', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '中央政府甲機關委由 A 開發公司辦理工程建造案，因 A 公司工程執行進度嚴重落後，爰甲機關 於X年10月與A公司終止契約，並向地方法院提出訴訟。X年會計年度終了日時，甲機關進行 評估，預期幾乎確定可從訴訟案件中獲得 A 公司 1 億元之履賠，依政府會計準則公報第 7 號規 定，下列敘述何者正確？', '["不作分錄，僅於附註揭露", "應認列資產及收入", "應認列資產但不認列收入", "應認列收入但不認列資產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00017', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依政府會計準則公報及中央總會計制度規定，下列事項中屬於財務報表之附註內容，計有幾項？', '["財務報表報導範圍", "採用之會計基礎", "政府代管或依法設立之信託基金資產、負債等情形 資訊", "依法應編預算送立法院之行政法人資產、負債等資訊  ⑤公務機關與特種基金間內部往 來事項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00018', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '公務人員退休撫卹基金 X4 年度收到銓敘部以當年度單位預算獎補助費科目對其撥補之款項 120 億元，依中央政府整體資產負債表編製注意事項規定，下列有關X4年12月31日中央政府整體 資產負債表之敘述，何者正確？', '["應彙總表達公務人員退休撫卹基金整體資產、負債等狀況", "公務機關欄位，帳列總會計科目（會計項目）「採權益法之投資」科目及「淨資產」科目", "內部往來沖銷欄位，應沖減總會計科目（會計項目）「押匯貼現、放款、基金」科目120億元", "內部往來沖銷欄位，無應沖減之總會計科目（會計項目）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00019', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-114-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，甲機關於X4年9月14日支付以前年度歲出保留 數100萬元，同年12月31日註銷不再執行之以前年度歲出預算保留數5萬元，均為經常門的保 留，對甲機關X4年度各類會計科目之影響，下列敘述何者正確？', '["減少負債100萬元", "減少負債105萬元", "增加收入100萬元", "均無影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:31+00:00", "source_pdf_sha1": "b53a452d1e18", "answer_pdf_sha1": "25217f9ea6aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "121", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
